   197→
   198→message NewPtyRequest {
   199→}
   200→
   201→message NewPtyResponse {
   202→	string master = 1;
   203→	uint32 master_fd = 2;
   204→	string slave = 3;
   205→	uint32 slave_fd = 4;
   206→}
   207→
   208→message SetPtySizeRequest {
