   225→message DirEntry {
   226→	string name = 1;
   227→	bool is_dir = 2;
   228→	int32 mode = 3;
   229→}
   230→
   231→message ReadDirResponse {
   232→	bool is_exist_err = 2;
   233→	bool is_not_exist_err = 3;
   234→	bool is_permission_err = 4;
   235→	repeated DirEntry path = 1;
   236→}
   237→
   238→message CommandPayload {
   239→	message Done {
   240→		string exit_error = 1;
   241→	}
   242→	message Started {
   243→		int64 pid = 1;
   244→	}
   245→	message IO {
   246→		enum Type {
   247→			TypeStdin = 0;
   248→			TypeStdout = 1;
   249→			TypeStderr = 2;
   250→		}
   251→		bytes data = 1;
   252→		Type type = 2;
   253→	}
   254→	enum Type {
   255→		TypeStart = 0;
   256→		TypeDone = 1;
   257→		TypeStarted = 2;
   258→		TypeIO = 3;
   259→		TypeError = 4;
   260→	}
   261→	Type type = 1;
   262→	StartCommandRequest start = 2;
   263→	Done done = 3;
   264→	Started started = 4;
   265→	IO io = 5;
   266→	string error = 6;
   267→}
   268→
   269→message MkdirAllRequest {
   270→	string path = 1;
   271→	int32 mode = 2;
   272→	string root = 3;
   273→}
   274→
   275→message MkdirAllResponse {
   276→	bool is_exist_err = 2;
   277→	bool is_not_exist_err = 3;
   278→	bool is_permission_err = 4;
   279→}
   280→
   281→enum Event {
   282→	Create = 0;
   283→	Remove = 1;
   284→	Write  = 2;
   285→	Rename = 3;
   286→}
   287→
   288→message WatchRequest {
   289→	string path = 1;
   290→	repeated Event events = 2;
   291→	string root = 3;
   292→}
   293→
   294→message WatchResponse {
   295→	int64 id = 1;
   296→}
   297→
   298→message WatchData {
   299→	Event event = 1;
   300→	string uri = 2;
   301→	bool is_dir = 4;
   302→}
   303→
   304→message WatchMessage {
   305→	enum Type {
   306→		TypeResponse = 0;
   307→		TypeData = 1;
   308→	}
   309→	Type type = 1;
   310→	WatchResponse response = 2;
   311→	WatchData data = 3;
   312→}
   313→
   314→message StopWatchRequest {
   315→	int64 id = 1;
   316→	string root = 2;
   317→}
   318→
   319→message StopWatchResponse {}
   320→
   321→message RootRequest {
   322→}
   323→
   324→message RootResponse {
   325→	string path = 1;
   326→}
   327→
   328→message SymlinkRequest {
   329→	string target = 1;
   330→	string link = 2;
   331→	string root = 3;
   332→}
   333→
   334→message SymlinkResponse {
   335→}
   336→
   337→message TempFileRequest {
   338→	string dir = 1;
   339→	string prefix = 2;
   340→	string root = 3;
   341→}
   342→
   343→message TempFileResponse {
   344→	string filename = 1;
   345→	uint32 fd = 2;
   346→}
   347→
   348→message JoinRequest {
   349→	repeated string elem = 1;
   350→}
   351→
   352→message JoinResponse {
   353→	string filename = 1;
   354→}
   355→
   356→service Terminal {
   357→	rpc NewPty(NewPtyRequest) returns (NewPtyResponse);
   358→	rpc SetPtySize(SetPtySizeRequest) returns (SetPtySizeResponse);
   359→}
   360→
   361→service Scheme {
   362→	rpc URI(URIRequest) returns (URIResponse);
   363→	rpc Open(OpenRequest) returns (OpenResponse);
   364→	rpc Remove(RemoveRequest) returns (RemoveResponse);
   365→	rpc Rename(RenameRequest) returns (RenameResponse);
   366→	rpc Stat(StatRequest) returns (StatResponse);
   367→	rpc ReadLink(ReadLinkRequest) returns (ReadLinkResponse);
   368→	rpc ReadDir(ReadDirRequest) returns (ReadDirResponse);
   369→	rpc MkdirAll(MkdirAllRequest) returns (MkdirAllResponse);
   370→	rpc Watch(WatchRequest) returns (stream WatchMessage) {};
   371→	rpc StopWatch(StopWatchRequest) returns (StopWatchResponse);
   372→	rpc Root(RootRequest) returns (RootResponse);
   373→	rpc Symlink(SymlinkRequest) returns (SymlinkResponse);
   374→	rpc TempFile(TempFileRequest) returns (TempFileResponse);
   375→	rpc Join(JoinRequest) returns (JoinResponse);
   376→}
   377→
   378→service Executor {
   379→	rpc StartCommand(stream CommandPayload) returns (stream CommandPayload) {};
   380→	rpc Signal(SignalRequest) returns (SignalResponse);
   381→}
   382→
   383→service Files {
   384→	rpc Sync(SyncRequest) returns (SyncResponse);
   385→	rpc Truncate(TruncateRequest) returns (TruncateResponse);
   386→	rpc Seek(SeekRequest) returns (SeekResponse);
   387→	rpc Close(CloseFileRequest) returns (CloseFileResponse);
   388→	rpc Read(ReadRequest) returns (ReadResponse);
   389→	rpc ReadAt(ReadRequest) returns (ReadResponse);
   390→	rpc Write(WriteRequest) returns (WriteResponse);
   391→	rpc Stat(StatRequest) returns (StatResponse);
   392→}
   393→
   394→service ProxyScheme {
   395→	rpc InitializeProxy(InitializeProxyRequest) returns (InitializeProxyResponse);
   396→}
   397→
   398→service Manager {
   399→	rpc RegisterScheme(RegisterSchemeRequest) returns (RegisterSchemeResponse);
   400→}
