     6→message CreateDocumentRequest {
     7→	string id = 1;
     8→	bytes data = 2;
     9→}
    10→
    11→message SetDocumentRequest {
    12→	string id = 1;
    13→	bytes data = 2;
    14→}
    15→
    16→message UpdateDocumentRequest {
    17→	string id = 1;
    18→
    19→	message Field {
    20→		repeated string field_path = 1;
    21→		bytes data = 2;
    22→	}
    23→
    24→	repeated Field updates = 2;
    25→	repeated Field preconditions = 3;
    26→}
    27→
    28→message GetDocumentRequest {
    29→	string id = 1;
    30→}
    31→
    32→message DeleteDocumentRequest {
    33→	string id = 1;
    34→}
    35→
    36→message ListDocumentRequest {
    37→	message Filter {
    38→		repeated string field_path = 1;
    39→		bytes data = 2;
    40→		string operation = 3;
    41→	}
    42→
    43→	repeated Filter filters = 1;
    44→}
    45→
    46→message DocumentResponse {
    47→}
    48→
    49→message GetDocumentResponse {
    50→	bytes data = 1;
    51→	bool not_found = 2;
    52→}
    53→message ListDocumentResponse {
    54→	bytes data = 1;
    55→	string error = 2;
    56→}
    57→message CreateDocumentResponse {
    58→	bool already_exists = 1;
    59→}
    60→message UpdateDocumentResponse {
    61→	bool not_found = 1;
    62→	bool precondition_failed = 2;
    63→}
    64→
    65→service DocumentStore {
    66→	rpc Create(CreateDocumentRequest) returns (CreateDocumentResponse);
    67→	rpc Set(SetDocumentRequest) returns (DocumentResponse);
    68→	rpc Update(UpdateDocumentRequest) returns (UpdateDocumentResponse);
    69→	rpc Get(GetDocumentRequest) returns (GetDocumentResponse);
    70→	rpc Delete(DeleteDocumentRequest) returns (DocumentResponse);
    71→	rpc List(ListDocumentRequest) returns (stream ListDocumentResponse);
    72→}
