    20→message EditResponse {
    21→}
    22→
    23→message EditorEvent {
    24→  enum Type {
    25→	TypeOpen = 0;
    26→	TypeClose = 1;
    27→	TypeFlush = 2;
    28→	TypeEdit = 3;
    29→	TypeScroll = 5;
    30→	TypeCreate = 12;
    31→	TypeChange = 13;
    32→	TypeFocus = 6;
    33→	TypeUnfocus = 7;
    34→	TypeCursor = 8;
    35→	TypeSelection = 9;
    36→	TypeRename = 10;
    37→	TypeRemove = 11;
    38→	TypeHidden = 14;
    39→	TypeVisible = 15;
    40→  }
    41→
    42→  Type type = 1;
