   120→// GetAttributes is a helper which extracts and parses a term.Attributes as a map
   121→// of fg, bg string keys to an attribute. See GetAttribute for more details.
   122→func GetAttributes(c Config, key string) (term.Attributes, error) {
   123→	cfg, err := c.GetConfig(key)
   124→	if err != nil {
   125→		return term.Attributes{}, err
   126→	}
   127→
   128→	var attr term.Attributes
   129→	attr.Attrs, err = cfg.GetAttribute("flag")
   130→	if err != nil && err != ErrNotFound {
   131→		return term.Attributes{}, fmt.Errorf("get 'flag': %w", err)
   132→	} else if err == ErrNotFound {
   133→		// try with 'flags' too
   134→		attr.Attrs, err = cfg.GetAttribute("flags")
   135→		if err != nil && err != ErrNotFound {
   136→			return term.Attributes{}, fmt.Errorf("get 'flags': %w", err)
   137→		}
   138→	}
   139→
   140→	if fg, err := cfg.GetColor("fg"); err == nil {
   141→		attr.Fg = fg
   142→	} else if err != ErrNotFound && err != nil {
   143→		return term.Attributes{}, fmt.Errorf("get 'fg' color: %w", err)
   144→	}
   145→
   146→	if bg, err := cfg.GetColor("bg"); err == nil {
   147→		attr.Bg = bg
   148→	} else if err != ErrNotFound && err != nil {
   149→		return term.Attributes{}, fmt.Errorf("get 'bg' color: %w", err)
   150→	}
   151→
   152→	return attr, nil
   153→}
