   322→func strToAttr(str string) (attr tcell.AttrMask, err error) {
   323→	switch str {
   324→	case "bold":
   325→		attr = tcell.AttrBold
   326→	case "underline":
   327→		attr = tcell.AttrUnderline
   328→	case "reverse":
   329→		attr = tcell.AttrReverse
   330→	case "default":
   331→		attr = tcell.AttrNone
   332→	case "none":
   333→		attr = tcell.AttrNone
   334→	case "blink":
   335→		attr = tcell.AttrBlink
   336→	case "dim":
   337→		attr = tcell.AttrDim
   338→	case "italic":
   339→		attr = tcell.AttrItalic
   340→	case "strikethrough":
   341→		attr = tcell.AttrStrikeThrough
   342→	default:
   343→		err = ErrInvalidAttributeValue
   344→	}
   345→	return
   346→}
