   348→func (c mapConfig) GetAttribute(key string) (tcell.AttrMask, error) {
   349→	v, ok := c[key]
   350→	if !ok {
   351→		return 0, ErrNotFound
   352→	}
   353→	vt, ok := v.(string)
   354→	if ok {
   355→		return strToAttr(vt)
   356→	}
   357→	i, err := c.GetInt(key)
   358→	if err == nil {
   359→		return tcell.AttrMask(i), nil
   360→	}
   361→
   362→	avt, ok := v.([]interface{})
   363→	if !ok {
   364→		return 0, ErrInvalidType
   365→	}
   366→
   367→	var attr tcell.AttrMask
   368→	for _, vtv := range avt {
   369→		if vtvs, ok := vtv.(string); ok {
   370→			vtvattr, err := strToAttr(vtvs)
   371→			if err != nil {
   372→				return 0, err
   373→			}
   374→			attr |= vtvattr
   375→		}
   376→	}
   377→
   378→	return attr, nil
   379→}
