   381→func (c mapConfig) GetColor(key string) (tcell.Color, error) {
   382→	v, ok := c[key]
   383→	if !ok {
   384→		return 0, ErrNotFound
   385→	}
   386→	vs, ok := v.(string)
   387→	if ok {
   388→		if vs == "default" {
   389→			return tcell.ColorDefault, nil
   390→		}
   391→		return tcell.GetColor(vs), nil
   392→	}
   393→	i, err := c.GetInt(key)
   394→	if err != nil {
   395→		return 0, err
   396→	}
   397→	if i > math.MaxInt32 {
   398→		return 0, ErrInvalidType
   399→	}
   400→	return tcell.NewHexColor(int32(i)), nil
