    28→
    29→var readBufferSize = 1024 * 64
    30→
    31→const watcherWaitTimeout = 2 * time.Minute
    32→
    33→type clientCommandStreamer struct {
    34→	req    *StartCommandRequest
    35→	cmd    workspaceapi.Cmd
    36→	log    *slog.Logger
    37→	stream Executor_StartCommandClient
    38→	ctx    context.Context
    39→	quitCh chan struct{}
    40→}
    41→
    42→func newClientCommandStreamer(
    43→	ctx context.Context,
    44→	req *StartCommandRequest,
    45→	cmd workspaceapi.Cmd,
    46→	stream Executor_StartCommandClient,
    47→) *clientCommandStreamer {
    48→	ret := new(clientCommandStreamer)
    49→	ret.cmd = cmd
    50→	ret.req = req
    51→	ret.stream = stream
    52→	ret.ctx = ctx
    53→	ret.quitCh = make(chan struct{})
    54→	ret.log = slog.Default().With("struct", "workspacerpc.clientCommandStream")
    55→	return ret
    56→}
    57→
    58→func (s *clientCommandStreamer) waitForPid() (workspaceapi.Pid, error) {
    59→	var msg CommandPayload
    60→	err := s.stream.RecvMsg(&msg)
    61→	s.log.Debug("receive first msg", "error", err)
    62→	if err != nil {
    63→		return 0, fmt.Errorf("stream receive msg: %v", err)
    64→	}
    65→
    66→	if msg.Type != CommandPayload_TypeStarted || msg.Started == nil {
    67→		return 0, fmt.Errorf("expected stream started msg, found %v", msg.Type)
    68→	}
    69→
    70→	return workspaceapi.Pid(msg.Started.Pid), nil
    71→}
    72→
    73→func (s *clientCommandStreamer) streamStdin() {
    74→	defer s.stream.CloseSend() // nolint:errcheck
    75→
    76→	if s.cmd.Stdin == nil {
    77→		s.log.Debug("no stdin set in cmd, skipping streaming stdin")
    78→		return
    79→	}
    80→
    81→	if s.req.StdinFd != 0 {
    82→		s.log.Debug("stdin is a file on the remote server. skipping streaming stdin")
    83→		return
    84→	}
    85→
    86→	var err error
    87→	buf := make([]byte, readBufferSize)
    88→	for {
    89→		select {
    90→		case <-s.quitCh:
    91→			return
    92→		case <-s.ctx.Done():
    93→			s.log.Debug("parent context is done")
    94→			return
    95→		default:
    96→		}
    97→
    98→		var n int
    99→		n, err = s.cmd.Stdin.Read(buf)
   100→		s.log.Debug("read from stdin", "error", err, "data", n)
   101→		if err != nil && err != io.EOF {
   102→			break
   103→		}
   104→		serr := s.stream.Send(&CommandPayload{
   105→			Type: CommandPayload_TypeIO,
   106→			Io: &CommandPayload_IO{
   107→				Data: buf[:n],
   108→				Type: CommandPayload_IO_TypeStdin,
   109→			},
   110→		})
   111→		if serr != nil {
   112→			err = fmt.Errorf("stream send: %v", serr)
   113→			break
   114→		}
   115→		if err == io.EOF {
   116→			err = nil
   117→			break
   118→		}
   119→	}
   120→
   121→	if err != nil {
   122→		s.log.Error("stream stdin stopped with error", "error", err)
   123→	}
   124→}
   125→
   126→func (s *clientCommandStreamer) streamCommandData(cancelFn func()) {
   127→	s.log.Debug("streaming command data")
   128→	defer close(s.quitCh)
   129→	defer cancelFn()
   130→
   131→	go debug.CapturePanicReport(s.streamStdin)
   132→
   133→	var err error
   134→	for {
   135→		var msg CommandPayload
   136→		err = s.stream.RecvMsg(&msg)
   137→		s.log.Debug("receive msg", "error", err)
   138→		if err != nil {
   139→			if err == io.EOF {
   140→				break
   141→			}
   142→			err = fmt.Errorf("stream receive msg: %v", err)
   143→			break
   144→		}
   145→
   146→		var n int
   147→		switch msg.Type {
   148→		case CommandPayload_TypeIO:
   149→			switch msg.GetIo().GetType() {
   150→			case CommandPayload_IO_TypeStdout:
   151→				if s.cmd.Stdout == nil {
   152→					s.log.Debug("no stdout set in cmd, dropping data")
   153→					continue
   154→				}
   155→				if s.req.StdoutFd != 0 {
   156→					s.log.Error("stdout is a file on the remote server but received data over the stream")
   157→					return
   158→				}
   159→				if msg.GetIo().Data == nil {
   160→					s.log.Warn("stdout type without stdout data")
   161→					continue
   162→				}
   163→				_, err = s.cmd.Stdout.Write(msg.GetIo().GetData())
   164→				s.log.Debug("wrote to stdout", "error", err, "data", len(msg.GetIo().GetData()))
   165→				if err != nil {
   166→					err = fmt.Errorf("stdout io.Writer write: %v", err)
   167→				}
   168→			case CommandPayload_IO_TypeStderr:
   169→				if s.cmd.Stderr == nil {
   170→					s.log.Debug("no stderr set in cmd, dropping data")
   171→					continue
   172→				}
   173→				if s.req.StderrFd != 0 {
   174→					s.log.Error("stderr is a file on the remote server but received data over the stream")
   175→					return
   176→				}
   177→				if msg.GetIo().Data == nil {
   178→					s.log.Warn("stderr type without stderr data")
   179→					continue
   180→				}
   181→				n, err = s.cmd.Stderr.Write(msg.GetIo().GetData())
   182→				s.log.Debug("wrote to stderr", "error", err, "data", n)
   183→				if err != nil {
   184→					err = fmt.Errorf("stderr io.Writer write: %v", err)
   185→				}
   186→			default:
   187→				err = fmt.Errorf("unexpected io message received %v", msg.GetType())
   188→			}
   189→			if err == nil {
   190→				continue
   191→			}
   192→		case CommandPayload_TypeError:
   193→			err = fmt.Errorf("error reading command stdio: %v", msg.GetError())
   194→		case CommandPayload_TypeDone:
   195→			if msg.GetDone().GetExitError() != "" {
   196→				err = errors.New(msg.GetDone().GetExitError())
   197→			}
   198→		default:
   199→			err = fmt.Errorf("unexpected message received %v", msg.GetType())
   200→		}
   201→		break
   202→	}
   203→
   204→	// avoid buggy watchers to cause this goroutine to block forever,
   205→	// so the timeout should be in the order of minutes.
   206→	ctx, cancel := context.WithTimeout(context.Background(),
   207→		watcherWaitTimeout)
   208→	defer cancel()
   209→
   210→	if s.cmd.Watcher != nil && s.cmd.Watcher.WatchProcess() != nil {
   211→		select {
   212→		case s.cmd.Watcher.WatchProcess() <- err:
   213→		case <-ctx.Done():
   214→			s.log.Warn("could not deliver error to watcher chan: " +
   215→				"watcher not ready for too long")
   216→		}
   217→	}
   218→	// emulate exec code; pipes should be closed to force EOF
   219→	for _, fd := range [2]io.Writer{s.cmd.Stdout, s.cmd.Stderr} {
   220→		if closer, ok := fd.(io.Closer); ok {
   221→			_ = closer.Close()
   222→		}
   223→	}
   224→	s.log.Debug("done streaming command data", "error", err)
   225→}
