   172→// OpenFile satisfies schemeapi.Scheme.
   173→func (c *Client) OpenFile(path string, flag int, mode os.FileMode) (
   174→	workspaceapi.File, error,
   175→) {
   176→	ctx, cleanup := ctxWithTimeout(c.ctx)
   177→	defer cleanup()
   178→
   179→	req := makeOpenRequest(c.root, path, flag, mode)
   180→	resp, err := c.scheme.Open(ctx, req)
   181→	if err != nil {
   182→		return nil, err
   183→	}
   184→	if werr, ok := isTypedError(resp); ok {
   185→		return nil, werr
   186→	}
   187→	ret := newFileClient(c.root, c.ctx, c, c.cc,
   188→		resp.GetFilename(), uintptr(resp.GetFd()))
   189→	return ret, nil
   190→}
