   192→// Stat returns a FileInfo describing the named file.
   193→func (c *Client) Stat(name string) (os.FileInfo, error) {
   194→	ctx, cleanup := ctxWithTimeout(c.ctx)
   195→	defer cleanup()
   196→
   197→	req := StatRequest{Root: c.root, Filename: name}
   198→	resp, err := c.scheme.Stat(ctx, &req)
   199→	if err != nil {
   200→		return nil, err
   201→	}
   202→	if werr, ok := isTypedError(resp); ok {
   203→		return nil, werr
   204→	}
   205→	return &fileClientInfo{StatResponse: *resp}, nil // nolint:govet
   206→}
