   208→// ReadDir reads the named directory, returning all its directory entries.
   209→func (c *Client) ReadDir(name string) ([]os.DirEntry, error) {
   210→	ctx, cleanup := ctxWithTimeout(c.ctx)
   211→	defer cleanup()
   212→
   213→	req := ReadDirRequest{Dir: name, Root: c.root}
   214→	resp, err := c.scheme.ReadDir(ctx, &req)
   215→	if err != nil {
   216→		return nil, err
   217→	}
   218→	if werr, ok := isTypedError(resp); ok {
   219→		return nil, werr
   220→	}
   221→	respp := resp.GetPath()
   222→	ret := make([]os.DirEntry, 0, len(respp))
   223→	for _, entry := range respp {
   224→		ret = append(ret, dirEntry{
   225→			c:        c,
   226→			name:     entry.Name,
   227→			isDir:    entry.IsDir,
   228→			modeType: entry.Mode,
   229→		})
   230→	}
   231→
   232→	return ret, nil
   233→}
