   283→// Readlink satisfies schemeapi.Scheme.
   284→func (c *Client) Readlink(filename string) (string, error) {
   285→	ctx, cleanup := ctxWithTimeout(c.ctx)
   286→	defer cleanup()
   287→
   288→	req := ReadLinkRequest{Root: c.root, Filename: filename}
   289→	resp, err := c.scheme.ReadLink(ctx, &req)
   290→	if err != nil {
   291→		return "", err
