   317→// StartCommand returns the Pid to execute the named program with the given
   318→// arguments. For more details see exec.Command.
   319→func (c *Client) StartCommand(
   320→	commandCtx context.Context, cmd workspaceapi.Cmd,
   321→) (workspaceapi.Pid, error) {
   322→	var cancelFn func()
   323→	commandCtx, cancelFn = mergeContexts(commandCtx, c.ctx)
   324→
   325→	stream, err := c.exec.StartCommand(commandCtx)
   326→	if err != nil {
   327→		cancelFn()
   328→		return 0, fmt.Errorf("new stream: %v", err)
   329→	}
   330→	var setsid, setctty bool
   331→	if cmd.SysProcAttr != nil {
   332→		setsid = cmd.SysProcAttr.Setsid
   333→		setctty = cmd.SysProcAttr.Setctty
   334→	}
   335→	req := CommandPayload{
   336→		Type: CommandPayload_TypeStart,
   337→		Start: &StartCommandRequest{
   338→			Name:    cmd.Path,
   339→			Dir:     cmd.Dir,
   340→			Args:    cmd.Args,
   341→			Env:     cmd.Env,
   342→			Stdin:   cmd.Stdin != nil,
   343→			Stdout:  cmd.Stdout != nil,
   344→			Stderr:  cmd.Stderr != nil,
   345→			Setsid:  setsid,
   346→			Setctty: setctty,
   347→		},
   348→	}
   349→	req.Start.StdinFd, req.Start.StdinName = tryUnwrapFile(cmd.Stdin)
   350→	req.Start.StdoutFd, req.Start.StdoutName = tryUnwrapFile(cmd.Stdout)
   351→	req.Start.StderrFd, req.Start.StderrName = tryUnwrapFile(cmd.Stderr)
   352→	streamer := newClientCommandStreamer(commandCtx, req.Start, cmd, stream)
   353→
   354→	type result struct {
   355→		pid workspaceapi.Pid
   356→		err error
   357→	}
   358→
   359→	// implement rpc timeout
   360→	handshakeCtx, cancel := context.WithTimeout(commandCtx, defaultTimeout)
   361→	defer cancel()
   362→
   363→	ch := make(chan result)
   364→	go debug.CapturePanicReport(func() {
   365→		// do not worry about closing stream here something else
   366→		// should take care of closing the connection if deemed appropiate.
   367→		if err := stream.Send(&req); err != nil {
   368→			res := result{err: fmt.Errorf("send start command request: %v", err)}
   369→			select {
   370→			case ch <- res:
   371→			case <-handshakeCtx.Done():
   372→			}
   373→			return
   374→		}
   375→		pid, err := streamer.waitForPid()
   376→		c.log.Debug("wait for pid", "pid", pid, "error", err)
   377→		if err != nil {
   378→			res := result{err: fmt.Errorf("error waiting for pid: %v", err)}
   379→			select {
   380→			case ch <- res:
   381→			case <-handshakeCtx.Done():
   382→			}
   383→			return
   384→		}
   385→		select {
   386→		case ch <- result{pid: pid}:
   387→		case <-handshakeCtx.Done():
   388→		}
   389→	})
   390→
   391→	select {
   392→	case res := <-ch:
   393→		if res.err != nil {
   394→			cancelFn()
   395→			return 0, res.err
   396→		}
   397→		go debug.CapturePanicReport(func() {
   398→			streamer.streamCommandData(cancelFn)
   399→		})
   400→		return res.pid, nil
   401→	case <-handshakeCtx.Done():
   402→		cancelFn()
   403→		return 0, handshakeCtx.Err()
   404→	}
   405→}
