	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	errchan := make(chan error, 1)
	go debug.CapturePanicReport(func() {
		errchan <- extension.ExtendWorkspace(ctx, workspace, config.MapConfig(req.Config))
	})

