	select {
	case err := <-errchan:
		if err != nil {
			slog.Error("extension is exiting", "error", err)
			return err
		}
		slog.Debug("extension was setup correctly")
		// Extension completed; wait for signal to exit
		<-sigchan
		return nil
	case <-sigchan:
