# Sandboxed Executor Implementation Plan

## 1. Overview

The goal is to create a `SandboxedExecutor` that wraps a sandbox VM runtime (using Matchlock as the underlying technology) to execute commands in an isolated environment while implementing the `workspaceapi.Executor` interface transparently.

## 2. Package Structure

Following the existing `api/<name>/` pattern:

```
api/
  sandboxapi/
    sandbox.go           # Core interfaces and types
    errors.go            # Error definitions
    generate.go          # Protobuf generation directive
    sandboxrpc/
      sandbox.proto      # gRPC service definitions for guest agent
      sandbox.pb.go      # Generated protobuf code
      sandbox_grpc.pb.go # Generated gRPC stubs
      client.go          # Guest agent client implementation
      stream.go          # Command streaming over vsock
    sandboxtest/
      nop_executor.go    # Test stub executor
      mock_sandbox.go    # Mock sandbox for testing
    policy/
      policy.go          # Security policy configuration
      network.go         # Network rules
      resources.go       # Resource limits
      filesystem.go      # Filesystem access rules
```

## 3. Core Types and Interfaces

### 3.1 Main Sandbox Interface (`api/sandboxapi/sandbox.go`)

```go
// Copyright 2026 Unstable Build, LLC.
// Licensed under the Apache License, Version 2.0

package sandboxapi

import (
    "context"
    "io"
    "syscall"

    "github.com/unstablebuild/rune-go-sdk/api/sandboxapi/policy"
    "github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
)

// Sandbox represents a running sandbox VM instance.
type Sandbox interface {
    // ID returns the unique identifier for this sandbox.
    ID() string

    // State returns the current sandbox state.
    State() SandboxState

    // Wait blocks until the sandbox terminates.
    Wait(context.Context) error

    // Destroy forcefully terminates the sandbox.
    Destroy(context.Context) error

    io.Closer
}

// SandboxState represents the lifecycle state of a sandbox.
type SandboxState int

const (
    SandboxStateUnknown SandboxState = iota
    SandboxStateInitializing
    SandboxStateRunning
    SandboxStateStopping
    SandboxStateStopped
    SandboxStateError
)

// Runtime abstracts the underlying VM technology.
type Runtime interface {
    // Create creates a new sandbox with the given configuration.
    Create(context.Context, *SandboxConfig) (Sandbox, error)

    // Platform returns the runtime's platform identifier.
    Platform() Platform

    io.Closer
}

// Platform identifies the underlying virtualization technology.
type Platform int

const (
    PlatformUnknown Platform = iota
    PlatformFirecracker      // Linux via Firecracker microVM
    PlatformAppleVF          // macOS via Virtualization.framework
)

// SandboxConfig holds configuration for creating a sandbox.
type SandboxConfig struct {
    // WorkspaceRoot is the host path to mount into the sandbox.
    WorkspaceRoot string

    // Policy defines security constraints for the sandbox.
    Policy *policy.Policy

    // Resources defines resource limits.
    Resources *ResourceConfig

    // Image specifies the guest VM image.
    Image string

    // Metadata is arbitrary key-value pairs for the sandbox.
    Metadata map[string]string
}

// ResourceConfig defines resource constraints for a sandbox.
type ResourceConfig struct {
    // CPUCount is the number of vCPUs to allocate.
    CPUCount int

    // MemoryMB is the amount of memory in megabytes.
    MemoryMB int

    // DiskMB is the maximum ephemeral disk size in megabytes.
    DiskMB int

    // NetworkBandwidthKbps is the maximum egress bandwidth.
    NetworkBandwidthKbps int
}
```

### 3.2 Executor Implementation (`api/sandboxapi/executor.go`)

```go
package sandboxapi

import (
    "context"
    "fmt"
    "io"
    "log/slog"
    "sync"
    "syscall"

    "github.com/unstablebuild/rune-go-sdk/api/sandboxapi/sandboxrpc"
    "github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
)

// Ensure interface compliance.
var _ workspaceapi.Executor = (*SandboxedExecutor)(nil)

// SandboxedExecutor implements workspaceapi.Executor by forwarding commands
// to a sandboxed guest VM.
type SandboxedExecutor struct {
    mu       sync.RWMutex
    runtime  Runtime
    sandbox  Sandbox
    agent    *sandboxrpc.AgentClient
    config   *SandboxConfig
    log      *slog.Logger
    ctx      context.Context
    cancelFn context.CancelFunc

    // lazily initialized
    initOnce sync.Once
    initErr  error
}

// NewSandboxedExecutor creates a new sandboxed executor with the given
// configuration.
func NewSandboxedExecutor(runtime Runtime, config *SandboxConfig) *SandboxedExecutor {
    ctx, cancel := context.WithCancel(context.Background())
    return &SandboxedExecutor{
        runtime:  runtime,
        config:   config,
        log:      slog.Default().With("struct", "sandboxapi.SandboxedExecutor"),
        ctx:      ctx,
        cancelFn: cancel,
    }
}

// Start implements workspaceapi.Executor.
func (e *SandboxedExecutor) Start(
    ctx context.Context, cmd workspaceapi.Cmd,
) (workspaceapi.Pid, error) {
    if err := e.ensureInitialized(ctx); err != nil {
        return 0, fmt.Errorf("sandbox initialization: %w", err)
    }

    e.mu.RLock()
    agent := e.agent
    e.mu.RUnlock()

    return agent.StartCommand(ctx, cmd)
}

// Signal implements workspaceapi.Executor.
func (e *SandboxedExecutor) Signal(pid workspaceapi.Pid, sig syscall.Signal) error {
    e.mu.RLock()
    agent := e.agent
    e.mu.RUnlock()

    if agent == nil {
        return ErrSandboxNotInitialized
    }

    return agent.Signal(pid, sig)
}

// Close implements io.Closer.
func (e *SandboxedExecutor) Close() error {
    e.cancelFn()

    e.mu.Lock()
    defer e.mu.Unlock()

    var errs []error
    if e.agent != nil {
        if err := e.agent.Close(); err != nil {
            errs = append(errs, fmt.Errorf("close agent: %w", err))
        }
    }
    if e.sandbox != nil {
        if err := e.sandbox.Close(); err != nil {
            errs = append(errs, fmt.Errorf("close sandbox: %w", err))
        }
    }

    if len(errs) > 0 {
        return fmt.Errorf("close errors: %v", errs)
    }
    return nil
}

// ensureInitialized lazily initializes the sandbox on first use.
func (e *SandboxedExecutor) ensureInitialized(ctx context.Context) error {
    e.initOnce.Do(func() {
        e.initErr = e.initialize(ctx)
    })
    return e.initErr
}

func (e *SandboxedExecutor) initialize(ctx context.Context) error {
    e.mu.Lock()
    defer e.mu.Unlock()

    e.log.Info("initializing sandbox")

    sandbox, err := e.runtime.Create(ctx, e.config)
    if err != nil {
        return fmt.Errorf("create sandbox: %w", err)
    }
    e.sandbox = sandbox

    // Connect to guest agent via vsock
    agent, err := sandboxrpc.NewAgentClient(ctx, sandbox)
    if err != nil {
        _ = sandbox.Destroy(ctx)
        return fmt.Errorf("connect to guest agent: %w", err)
    }
    e.agent = agent

    e.log.Info("sandbox initialized", "id", sandbox.ID())
    return nil
}
```

### 3.3 Guest Agent Protocol (`api/sandboxapi/sandboxrpc/sandbox.proto`)

```protobuf
syntax = "proto3";

option go_package = "github.com/unstablebuild/rune-go-sdk/api/sandboxapi/sandboxrpc";

package sandbox;

// AgentService runs inside the guest VM and handles command execution.
service AgentService {
    // StartCommand starts a command and streams I/O.
    rpc StartCommand(stream CommandMessage) returns (stream CommandMessage);

    // Signal sends a signal to a running process.
    rpc Signal(SignalRequest) returns (SignalResponse);

    // Ping verifies the agent is responsive.
    rpc Ping(PingRequest) returns (PingResponse);

    // Shutdown requests graceful shutdown of the guest.
    rpc Shutdown(ShutdownRequest) returns (ShutdownResponse);
}

message CommandMessage {
    enum Type {
        TypeStart = 0;
        TypeStarted = 1;
        TypeIO = 2;
        TypeDone = 3;
        TypeError = 4;
    }

    Type type = 1;
    StartCommandRequest start = 2;
    StartedResponse started = 3;
    IOData io = 4;
    DoneResponse done = 5;
    string error = 6;
}

message StartCommandRequest {
    string path = 1;
    string dir = 2;
    repeated string args = 3;
    repeated string env = 4;
    bool stdin = 5;
    bool stdout = 6;
    bool stderr = 7;
}

message StartedResponse {
    int64 pid = 1;
}

message IOData {
    enum Stream {
        Stdin = 0;
        Stdout = 1;
        Stderr = 2;
    }
    Stream stream = 1;
    bytes data = 2;
}

message DoneResponse {
    int32 exit_code = 1;
    string exit_error = 2;
}

message SignalRequest {
    int64 pid = 1;
    int32 signal = 2;
}

message SignalResponse {}

message PingRequest {}

message PingResponse {
    string version = 1;
}

message ShutdownRequest {
    int32 timeout_seconds = 1;
}

message ShutdownResponse {}
```

### 3.4 Policy Configuration (`api/sandboxapi/policy/policy.go`)

```go
package policy

// Policy defines the security constraints for a sandbox.
type Policy struct {
    // Network defines network access rules.
    Network *NetworkPolicy

    // Filesystem defines filesystem access rules.
    Filesystem *FilesystemPolicy

    // Environment defines environment variable handling.
    Environment *EnvironmentPolicy

    // Audit enables audit logging.
    Audit *AuditPolicy
}

// DefaultPolicy returns a secure default policy.
func DefaultPolicy() *Policy {
    return &Policy{
        Network: &NetworkPolicy{
            DefaultEgress: DenyEgress,
            AllowedDomains: nil,
            AllowListen:   false,
        },
        Filesystem: &FilesystemPolicy{
            ReadOnlyPaths:  []string{"/usr", "/bin", "/lib"},
            WritablePaths:  []string{"/tmp", "/workspace"},
            BlockedPaths:   []string{"/etc/passwd", "/etc/shadow"},
            EphemeralRoot:  true,
        },
        Environment: &EnvironmentPolicy{
            ScrubSecrets:     true,
            SecretPatterns:   defaultSecretPatterns,
            AllowedVariables: nil, // nil means allow all non-secrets
        },
        Audit: &AuditPolicy{
            LogCommands:    true,
            LogFileAccess:  true,
            LogNetworkReqs: true,
        },
    }
}

// NetworkPolicy defines network access constraints.
type NetworkPolicy struct {
    // DefaultEgress is the default egress policy.
    DefaultEgress EgressPolicy

    // AllowedDomains is a list of domains permitted for egress.
    AllowedDomains []string

    // AllowListen permits binding to listening sockets.
    AllowListen bool

    // AllowedPorts restricts which ports can be accessed.
    AllowedPorts []int
}

// EgressPolicy defines the default egress behavior.
type EgressPolicy int

const (
    DenyEgress  EgressPolicy = iota // Block all outbound by default
    AllowEgress                      // Allow all outbound by default
)

// FilesystemPolicy defines filesystem access constraints.
type FilesystemPolicy struct {
    // ReadOnlyPaths are mounted read-only in the sandbox.
    ReadOnlyPaths []string

    // WritablePaths are mounted writable in the sandbox.
    WritablePaths []string

    // BlockedPaths are completely inaccessible.
    BlockedPaths []string

    // EphemeralRoot makes the root filesystem ephemeral (changes lost).
    EphemeralRoot bool
}

// EnvironmentPolicy defines environment variable handling.
type EnvironmentPolicy struct {
    // ScrubSecrets removes detected secrets from environment.
    ScrubSecrets bool

    // SecretPatterns are regex patterns to detect secrets.
    SecretPatterns []string

    // AllowedVariables is an allowlist; nil allows all non-secrets.
    AllowedVariables []string
}

// AuditPolicy defines what actions are logged.
type AuditPolicy struct {
    LogCommands    bool
    LogFileAccess  bool
    LogNetworkReqs bool
}

var defaultSecretPatterns = []string{
    `(?i)(api[_-]?key|apikey)`,
    `(?i)(secret[_-]?key|secretkey)`,
    `(?i)(access[_-]?token|accesstoken)`,
    `(?i)(password|passwd|pwd)`,
    `(?i)(private[_-]?key|privatekey)`,
    `(?i)(auth[_-]?token|authtoken)`,
    `(?i)(aws[_-]?secret)`,
    `(?i)(github[_-]?token)`,
