### 7.2 Transparent Wrapper

For fully transparent usage, callers can use a wrapper that chooses the appropriate executor:

```go
// api/sandboxapi/transparent.go

package sandboxapi

import (
    "context"
    "syscall"

    "github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
)

// TransparentExecutor wraps either a sandboxed or native executor.
type TransparentExecutor struct {
    native  workspaceapi.Executor
    sandbox workspaceapi.Executor
    useSandbox bool
}

// NewTransparentExecutor creates an executor that can transparently
// switch between sandboxed and native execution.
func NewTransparentExecutor(
    native, sandbox workspaceapi.Executor,
    useSandbox bool,
) *TransparentExecutor {
    return &TransparentExecutor{
        native:     native,
        sandbox:    sandbox,
        useSandbox: useSandbox,
    }
}

func (e *TransparentExecutor) Start(
    ctx context.Context, cmd workspaceapi.Cmd,
) (workspaceapi.Pid, error) {
    if e.useSandbox && e.sandbox != nil {
        return e.sandbox.Start(ctx, cmd)
    }
    return e.native.Start(ctx, cmd)
}

func (e *TransparentExecutor) Signal(
    pid workspaceapi.Pid, sig syscall.Signal,
) error {
    if e.useSandbox && e.sandbox != nil {
        return e.sandbox.Signal(pid, sig)
    }
    return e.native.Signal(pid, sig)
}

func (e *TransparentExecutor) Close() error {
    var errs []error
    if e.sandbox != nil {
        if err := e.sandbox.Close(); err != nil {
            errs = append(errs, err)
        }
    }
    if e.native != nil {
        if err := e.native.Close(); err != nil {
            errs = append(errs, err)
        }
    }
    if len(errs) > 0 {
        return errs[0]
    }
    return nil
}
```

