```go
package sandboxtest

import (
    "context"
    "sync"
    "syscall"

    "github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
)

// MockSandbox allows testing sandbox behavior without actual VMs.
type MockSandbox struct {
    mu       sync.Mutex
    commands []workspaceapi.Cmd
    signals  []struct {
        Pid workspaceapi.Pid
        Sig syscall.Signal
    }
    nextPid workspaceapi.Pid
    StartFn func(context.Context, workspaceapi.Cmd) (workspaceapi.Pid, error)
}

func NewMockSandbox() *MockSandbox {
    return &MockSandbox{nextPid: 1000}
}

func (m *MockSandbox) Start(
    ctx context.Context, cmd workspaceapi.Cmd,
) (workspaceapi.Pid, error) {
    m.mu.Lock()
    defer m.mu.Unlock()

    if m.StartFn != nil {
        return m.StartFn(ctx, cmd)
    }

    m.commands = append(m.commands, cmd)
    pid := m.nextPid
    m.nextPid++
    return pid, nil
}

func (m *MockSandbox) Signal(pid workspaceapi.Pid, sig syscall.Signal) error {
    m.mu.Lock()
    defer m.mu.Unlock()

    m.signals = append(m.signals, struct {
        Pid workspaceapi.Pid
        Sig syscall.Signal
    }{pid, sig})
    return nil
}

func (m *MockSandbox) Close() error {
    return nil
}

// Commands returns all commands that were started.
func (m *MockSandbox) Commands() []workspaceapi.Cmd {
    m.mu.Lock()
    defer m.mu.Unlock()
    return append([]workspaceapi.Cmd{}, m.commands...)
}

// Signals returns all signals that were sent.
func (m *MockSandbox) Signals() []struct {
    Pid workspaceapi.Pid
    Sig syscall.Signal
} {
    m.mu.Lock()
    defer m.mu.Unlock()
    ret := make([]struct {
        Pid workspaceapi.Pid
        Sig syscall.Signal
    }, len(m.signals))
    copy(ret, m.signals)
    return ret
}
