// Sandbox represents a running sandbox VM instance.
type Sandbox interface {
    // ID returns the unique identifier for this sandbox.
    ID() string

    // State returns the current sandbox state.
    State() SandboxState

    // Wait blocks until the sandbox terminates.
    Wait(context.Context) error

    // Destroy forcefully terminates the sandbox.
    Destroy(context.Context) error

    io.Closer
}

// SandboxState represents the lifecycle state of a sandbox.
type SandboxState int

const (
    SandboxStateUnknown SandboxState = iota
    SandboxStateInitializing
    SandboxStateRunning
    SandboxStateStopping
    SandboxStateStopped
    SandboxStateError
)

// Runtime abstracts the underlying VM technology.
type Runtime interface {
    // Create creates a new sandbox with the given configuration.
    Create(context.Context, *SandboxConfig) (Sandbox, error)

    // Platform returns the runtime's platform identifier.
    Platform() Platform

    io.Closer
}

// Platform identifies the underlying virtualization technology.
type Platform int

const (
    PlatformUnknown Platform = iota
    PlatformFirecracker      // Linux via Firecracker microVM
    PlatformAppleVF          // macOS via Virtualization.framework
)

// SandboxConfig holds configuration for creating a sandbox.
type SandboxConfig struct {
    // WorkspaceRoot is the host path to mount into the sandbox.
    WorkspaceRoot string

    // Policy defines security constraints for the sandbox.
    Policy *policy.Policy

    // Resources defines resource limits.
    Resources *ResourceConfig

    // Image specifies the guest VM image.
    Image string

    // Metadata is arbitrary key-value pairs for the sandbox.
    Metadata map[string]string
}

// ResourceConfig defines resource constraints for a sandbox.
type ResourceConfig struct {
    // CPUCount is the number of vCPUs to allocate.
    CPUCount int

    // MemoryMB is the amount of memory in megabytes.
    MemoryMB int

    // DiskMB is the maximum ephemeral disk size in megabytes.
    DiskMB int

    // NetworkBandwidthKbps is the maximum egress bandwidth.
    NetworkBandwidthKbps int
