### 3.2 Executor Implementation (`api/sandboxapi/executor.go`)

```go
package sandboxapi

import (
    "context"
    "fmt"
    "io"
    "log/slog"
    "sync"
    "syscall"

    "github.com/unstablebuild/rune-go-sdk/api/sandboxapi/sandboxrpc"
    "github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
)

// Ensure interface compliance.
var _ workspaceapi.Executor = (*SandboxedExecutor)(nil)

// SandboxedExecutor implements workspaceapi.Executor by forwarding commands
// to a sandboxed guest VM.
type SandboxedExecutor struct {
    mu       sync.RWMutex
    runtime  Runtime
    sandbox  Sandbox
    agent    *sandboxrpc.AgentClient
    config   *SandboxConfig
    log      *slog.Logger
    ctx      context.Context
    cancelFn context.CancelFunc

    // lazily initialized
    initOnce sync.Once
    initErr  error
}

// NewSandboxedExecutor creates a new sandboxed executor with the given
// configuration.
func NewSandboxedExecutor(runtime Runtime, config *SandboxConfig) *SandboxedExecutor {
    ctx, cancel := context.WithCancel(context.Background())
    return &SandboxedExecutor{
        runtime:  runtime,
        config:   config,
        log:      slog.Default().With("struct", "sandboxapi.SandboxedExecutor"),
        ctx:      ctx,
        cancelFn: cancel,
    }
}

// Start implements workspaceapi.Executor.
func (e *SandboxedExecutor) Start(
    ctx context.Context, cmd workspaceapi.Cmd,
) (workspaceapi.Pid, error) {
    if err := e.ensureInitialized(ctx); err != nil {
        return 0, fmt.Errorf("sandbox initialization: %w", err)
    }

    e.mu.RLock()
    agent := e.agent
    e.mu.RUnlock()

    return agent.StartCommand(ctx, cmd)
}

// Signal implements workspaceapi.Executor.
func (e *SandboxedExecutor) Signal(pid workspaceapi.Pid, sig syscall.Signal) error {
    e.mu.RLock()
    agent := e.agent
    e.mu.RUnlock()

    if agent == nil {
        return ErrSandboxNotInitialized
    }

    return agent.Signal(pid, sig)
}

// Close implements io.Closer.
func (e *SandboxedExecutor) Close() error {
    e.cancelFn()

    e.mu.Lock()
    defer e.mu.Unlock()

    var errs []error
    if e.agent != nil {
        if err := e.agent.Close(); err != nil {
            errs = append(errs, fmt.Errorf("close agent: %w", err))
        }
    }
    if e.sandbox != nil {
        if err := e.sandbox.Close(); err != nil {
            errs = append(errs, fmt.Errorf("close sandbox: %w", err))
        }
    }

    if len(errs) > 0 {
        return fmt.Errorf("close errors: %v", errs)
    }
    return nil
}

// ensureInitialized lazily initializes the sandbox on first use.
func (e *SandboxedExecutor) ensureInitialized(ctx context.Context) error {
    e.initOnce.Do(func() {
        e.initErr = e.initialize(ctx)
    })
    return e.initErr
}

func (e *SandboxedExecutor) initialize(ctx context.Context) error {
    e.mu.Lock()
    defer e.mu.Unlock()

    e.log.Info("initializing sandbox")

    sandbox, err := e.runtime.Create(ctx, e.config)
    if err != nil {
        return fmt.Errorf("create sandbox: %w", err)
    }
    e.sandbox = sandbox

    // Connect to guest agent via vsock
    agent, err := sandboxrpc.NewAgentClient(ctx, sandbox)
    if err != nil {
        _ = sandbox.Destroy(ctx)
        return fmt.Errorf("connect to guest agent: %w", err)
    }
    e.agent = agent

    e.log.Info("sandbox initialized", "id", sandbox.ID())
    return nil
}
```

### 3.3 Guest Agent Protocol (`api/sandboxapi/sandboxrpc/sandbox.proto`)

```protobuf
syntax = "proto3";

option go_package = "github.com/unstablebuild/rune-go-sdk/api/sandboxapi/sandboxrpc";

package sandbox;

// AgentService runs inside the guest VM and handles command execution.
service AgentService {
    // StartCommand starts a command and streams I/O.
    rpc StartCommand(stream CommandMessage) returns (stream CommandMessage);

    // Signal sends a signal to a running process.
    rpc Signal(SignalRequest) returns (SignalResponse);

    // Ping verifies the agent is responsive.
    rpc Ping(PingRequest) returns (PingResponse);

    // Shutdown requests graceful shutdown of the guest.
    rpc Shutdown(ShutdownRequest) returns (ShutdownResponse);
}

message CommandMessage {
    enum Type {
        TypeStart = 0;
        TypeStarted = 1;
        TypeIO = 2;
        TypeDone = 3;
        TypeError = 4;
    }

    Type type = 1;
    StartCommandRequest start = 2;
    StartedResponse started = 3;
    IOData io = 4;
    DoneResponse done = 5;
    string error = 6;
}

message StartCommandRequest {
    string path = 1;
    string dir = 2;
    repeated string args = 3;
    repeated string env = 4;
    bool stdin = 5;
    bool stdout = 6;
    bool stderr = 7;
}

message StartedResponse {
    int64 pid = 1;
}

message IOData {
    enum Stream {
        Stdin = 0;
        Stdout = 1;
        Stderr = 2;
    }
    Stream stream = 1;
    bytes data = 2;
}

message DoneResponse {
    int32 exit_code = 1;
    string exit_error = 2;
}

message SignalRequest {
    int64 pid = 1;
    int32 signal = 2;
}

message SignalResponse {}

message PingRequest {}

message PingResponse {
    string version = 1;
}

message ShutdownRequest {
    int32 timeout_seconds = 1;
}

message ShutdownResponse {}
