### 3.4 Policy Configuration (`api/sandboxapi/policy/policy.go`)

```go
package policy

// Policy defines the security constraints for a sandbox.
type Policy struct {
    // Network defines network access rules.
    Network *NetworkPolicy

    // Filesystem defines filesystem access rules.
    Filesystem *FilesystemPolicy

    // Environment defines environment variable handling.
    Environment *EnvironmentPolicy

    // Audit enables audit logging.
    Audit *AuditPolicy
}

// DefaultPolicy returns a secure default policy.
func DefaultPolicy() *Policy {
    return &Policy{
        Network: &NetworkPolicy{
            DefaultEgress: DenyEgress,
            AllowedDomains: nil,
            AllowListen:   false,
        },
        Filesystem: &FilesystemPolicy{
            ReadOnlyPaths:  []string{"/usr", "/bin", "/lib"},
            WritablePaths:  []string{"/tmp", "/workspace"},
            BlockedPaths:   []string{"/etc/passwd", "/etc/shadow"},
            EphemeralRoot:  true,
        },
        Environment: &EnvironmentPolicy{
            ScrubSecrets:     true,
            SecretPatterns:   defaultSecretPatterns,
            AllowedVariables: nil, // nil means allow all non-secrets
        },
        Audit: &AuditPolicy{
            LogCommands:    true,
            LogFileAccess:  true,
            LogNetworkReqs: true,
        },
    }
}

// NetworkPolicy defines network access constraints.
type NetworkPolicy struct {
    // DefaultEgress is the default egress policy.
    DefaultEgress EgressPolicy

    // AllowedDomains is a list of domains permitted for egress.
    AllowedDomains []string

    // AllowListen permits binding to listening sockets.
    AllowListen bool

    // AllowedPorts restricts which ports can be accessed.
    AllowedPorts []int
}

// EgressPolicy defines the default egress behavior.
type EgressPolicy int

const (
    DenyEgress  EgressPolicy = iota // Block all outbound by default
    AllowEgress                      // Allow all outbound by default
)

// FilesystemPolicy defines filesystem access constraints.
type FilesystemPolicy struct {
    // ReadOnlyPaths are mounted read-only in the sandbox.
    ReadOnlyPaths []string

    // WritablePaths are mounted writable in the sandbox.
    WritablePaths []string

    // BlockedPaths are completely inaccessible.
    BlockedPaths []string

    // EphemeralRoot makes the root filesystem ephemeral (changes lost).
    EphemeralRoot bool
}

// EnvironmentPolicy defines environment variable handling.
type EnvironmentPolicy struct {
    // ScrubSecrets removes detected secrets from environment.
    ScrubSecrets bool

    // SecretPatterns are regex patterns to detect secrets.
    SecretPatterns []string

    // AllowedVariables is an allowlist; nil allows all non-secrets.
    AllowedVariables []string
}

// AuditPolicy defines what actions are logged.
type AuditPolicy struct {
    LogCommands    bool
    LogFileAccess  bool
    LogNetworkReqs bool
}

var defaultSecretPatterns = []string{
    `(?i)(api[_-]?key|apikey)`,
    `(?i)(secret[_-]?key|secretkey)`,
    `(?i)(access[_-]?token|accesstoken)`,
    `(?i)(password|passwd|pwd)`,
    `(?i)(private[_-]?key|privatekey)`,
    `(?i)(auth[_-]?token|authtoken)`,
    `(?i)(aws[_-]?secret)`,
    `(?i)(github[_-]?token)`,
    `(?i)(database[_-]?url|db[_-]?url)`,
}
