## 5. Guest Agent Client (`api/sandboxapi/sandboxrpc/client.go`)

```go
package sandboxrpc

import (
    "context"
    "fmt"
    "io"
    "log/slog"
    "sync"
    "syscall"
    "time"

    "github.com/unstablebuild/rune-go-sdk/api/sandboxapi"
    "github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
    "github.com/unstablebuild/rune-go-sdk/debug"
    "google.golang.org/grpc"
)

const (
    defaultAgentTimeout = 30 * time.Second
    vsockPort           = 1024
)

// AgentClient communicates with the guest agent over vsock.
type AgentClient struct {
    conn    *grpc.ClientConn
    client  AgentServiceClient
    sandbox sandboxapi.Sandbox
    log     *slog.Logger
    ctx     context.Context
    cancel  context.CancelFunc
}

// NewAgentClient connects to the guest agent in the given sandbox.
func NewAgentClient(
    ctx context.Context, sandbox sandboxapi.Sandbox,
) (*AgentClient, error) {
    ctx, cancel := context.WithCancel(ctx)

    // Connect via vsock to guest agent
    conn, err := dialVsock(ctx, sandbox, vsockPort)
    if err != nil {
        cancel()
        return nil, fmt.Errorf("dial vsock: %w", err)
    }

    client := NewAgentServiceClient(conn)

    // Verify agent is responsive
    pingCtx, pingCancel := context.WithTimeout(ctx, defaultAgentTimeout)
    defer pingCancel()

    _, err = client.Ping(pingCtx, &PingRequest{})
    if err != nil {
        _ = conn.Close()
        cancel()
        return nil, fmt.Errorf("ping agent: %w", err)
    }

    return &AgentClient{
        conn:    conn,
        client:  client,
        sandbox: sandbox,
        log:     slog.Default().With("struct", "sandboxrpc.AgentClient"),
        ctx:     ctx,
        cancel:  cancel,
    }, nil
}

// StartCommand starts a command in the sandbox and streams I/O.
func (c *AgentClient) StartCommand(
    ctx context.Context, cmd workspaceapi.Cmd,
) (workspaceapi.Pid, error) {
    stream, err := c.client.StartCommand(ctx)
    if err != nil {
        return 0, fmt.Errorf("start command stream: %w", err)
    }

    // Send start request
    req := &CommandMessage{
        Type: CommandMessage_TypeStart,
        Start: &StartCommandRequest{
            Path:   cmd.Path,
            Dir:    cmd.Dir,
            Args:   cmd.Args,
            Env:    cmd.Env,
            Stdin:  cmd.Stdin != nil,
            Stdout: cmd.Stdout != nil,
            Stderr: cmd.Stderr != nil,
        },
    }

    if err := stream.Send(req); err != nil {
        return 0, fmt.Errorf("send start request: %w", err)
    }

    // Wait for started response
    msg, err := stream.Recv()
    if err != nil {
        return 0, fmt.Errorf("recv started response: %w", err)
    }

    if msg.Type != CommandMessage_TypeStarted {
        return 0, fmt.Errorf("expected started message, got %v", msg.Type)
    }

    pid := workspaceapi.Pid(msg.Started.Pid)

    // Start I/O streaming goroutine
    streamer := newCommandStreamer(ctx, cmd, stream, c.log)
    go debug.CapturePanicReport(streamer.streamIO)

    return pid, nil
}

// Signal sends a signal to a process in the sandbox.
func (c *AgentClient) Signal(pid workspaceapi.Pid, sig syscall.Signal) error {
    ctx, cancel := context.WithTimeout(c.ctx, defaultAgentTimeout)
    defer cancel()

    _, err := c.client.Signal(ctx, &SignalRequest{
        Pid:    int64(pid),
        Signal: int32(sig),
    })
    return err
}

// Close closes the connection to the guest agent.
func (c *AgentClient) Close() error {
    c.cancel()
    return c.conn.Close()
}
```

## 6. Command Streaming (`api/sandboxapi/sandboxrpc/stream.go`)

```go
package sandboxrpc

import (
    "context"
    "errors"
    "io"
    "log/slog"

    "github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
)

const ioBufferSize = 64 * 1024

type commandStreamer struct {
    ctx    context.Context
    cmd    workspaceapi.Cmd
    stream AgentService_StartCommandClient
    log    *slog.Logger
    quitCh chan struct{}
}

func newCommandStreamer(
    ctx context.Context,
    cmd workspaceapi.Cmd,
    stream AgentService_StartCommandClient,
    log *slog.Logger,
) *commandStreamer {
    return &commandStreamer{
        ctx:    ctx,
        cmd:    cmd,
        stream: stream,
        log:    log,
        quitCh: make(chan struct{}),
    }
}

func (s *commandStreamer) streamIO() {
    defer close(s.quitCh)

    // Start stdin streaming if needed
    if s.cmd.Stdin != nil {
        go s.streamStdin()
    }

    // Receive stdout/stderr and completion
    var finalErr error
    for {
        msg, err := s.stream.Recv()
        if err != nil {
            if err != io.EOF {
                finalErr = err
            }
            break
        }

        switch msg.Type {
        case CommandMessage_TypeIO:
            s.handleIO(msg.Io)
        case CommandMessage_TypeDone:
            if msg.Done.ExitError != "" {
                finalErr = errors.New(msg.Done.ExitError)
            }
        case CommandMessage_TypeError:
            finalErr = errors.New(msg.Error)
        }

        if msg.Type == CommandMessage_TypeDone || msg.Type == CommandMessage_TypeError {
            break
        }
    }

    // Notify watcher
    if s.cmd.Watcher != nil && s.cmd.Watcher.WatchProcess() != nil {
        select {
        case s.cmd.Watcher.WatchProcess() <- finalErr:
        case <-s.ctx.Done():
        }
    }

    // Close outputs
    for _, w := range []io.Writer{s.cmd.Stdout, s.cmd.Stderr} {
        if closer, ok := w.(io.Closer); ok {
            _ = closer.Close()
        }
    }
}

func (s *commandStreamer) streamStdin() {
    defer s.stream.CloseSend()

    buf := make([]byte, ioBufferSize)
    for {
        select {
        case <-s.quitCh:
            return
        case <-s.ctx.Done():
            return
        default:
        }

        n, err := s.cmd.Stdin.Read(buf)
        if n > 0 {
            msg := &CommandMessage{
                Type: CommandMessage_TypeIO,
                Io: &IOData{
                    Stream: IOData_Stdin,
                    Data:   buf[:n],
                },
            }
            if serr := s.stream.Send(msg); serr != nil {
                s.log.Error("send stdin", "error", serr)
                return
            }
        }
        if err != nil {
            if err != io.EOF {
                s.log.Error("read stdin", "error", err)
            }
            return
        }
    }
}

func (s *commandStreamer) handleIO(data *IOData) {
    var w io.Writer
    switch data.Stream {
    case IOData_Stdout:
        w = s.cmd.Stdout
    case IOData_Stderr:
        w = s.cmd.Stderr
    default:
        return
    }

    if w == nil {
        return
    }

    if _, err := w.Write(data.Data); err != nil {
        s.log.Error("write output", "stream", data.Stream, "error", err)
    }
}
```

